#!/usr/bin/env node
const fs = require('fs');
const path = require('path');
const zlib = require('zlib');

const runnerTemp = process.env.RUNNER_TEMP || '/tmp';
const dest = process.env.DEST || path.join(runnerTemp, 'triage-summary.md');
const stepSummary = process.env.GITHUB_STEP_SUMMARY || '.github/actions-runs/step-summary.txt';
const triagePath = process.env.TRIAGE_INPUT || 'builds/diagnostics/triage.json';

function safeRead(p){ try { return fs.readFileSync(p,'utf8'); } catch(e){ return null; } }

const triageRaw = safeRead(triagePath);
let triage = null;
if (triageRaw){ try { triage = JSON.parse(triageRaw); } catch(e){ triage = null; } }

const stepSum = safeRead(stepSummary) || '';

function mdEscape(s){ return String(s).replace(/\|/g,'\\|'); }
function shortSummaryFrom(j){
  if (!j) return 'No summary available.';
  if (j.summary && j.summary.length < 200) return j.summary;
  const errs = (j.internalErrors||[]);
  if (errs.length) return String(errs[0]).split('\n')[0].slice(0,180) + (String(errs[0]).length>180?'…':'');
  if (j.inferredTags && j.inferredTags.length) return 'Tags: '+j.inferredTags.slice(0,3).join(', ');
  return 'No concise summary available.';
}

let md = '';
md += '# Triage Summary\n\n';
md += '---\n\n';

// Overview table
md += '## Overview\n\n';
md += '| Severity | Tags | Internal Errors | Timestamp |\n';
md += '|---:|---|---:|---|\n';

if (triage){
  const severity = triage.severity || 'unknown';
  const tags = (triage.inferredTags||[]).join(', ') || 'none';
  const errCount = (triage.internalErrors||[]).length || 0;
  const timestamp = triage.timestamp || new Date().toISOString();
  md += `| **${mdEscape(severity)}** | ${mdEscape(tags)} | ${errCount} | ${timestamp} |\n\n`;
} else {
  md += '| _unknown_ | none | 0 | - |\n\n';
}

// Summary line
md += '### Summary\n\n';
md += '> ' + shortSummaryFrom(triage) + '\n\n';

// issue info
const issueLine = (stepSum.match(/- triage issue: .*$/m)||[])[0] || '';
if (issueLine) md += '**Issue:** ' + issueLine + '\n\n';

md += '---\n\n';

// Details with folding for long content
md += '<details>\n<summary>Details (expand for full JSON and internal errors)</summary>\n\n';
if (triageRaw){
  // Pretty JSON block
  try {
    const parsed = JSON.parse(triageRaw);
    md += '```json\n' + JSON.stringify(parsed, null, 2) + '\n```\n\n';
    // Internal errors folded
    const internal = (parsed.internalErrors || []).map(e=>String(e));
    if (internal.length){
      md += '<details>\n<summary>Internal Errors ('+internal.length+')</summary>\n\n';
      const joined = internal.join('\n\n');
      const MAX_INLINE = 50000;
      const needExtract = joined.length > MAX_INLINE;
      // if very long, write full errors to runner temp and show preview in MD/HTML
      if (needExtract){
        try {
          const iePath = path.join(runnerTemp, 'triage-internal-errors.txt');
          fs.writeFileSync(iePath, joined, 'utf8');
          md += '```text\n' + joined.slice(0,MAX_INLINE) + '\n\n... (truncated; full internal errors in triage-internal-errors.txt)\n```\n\n';
        } catch(e){
          md += '```text\n' + joined.slice(0,MAX_INLINE) + '\n\n... (truncated)\n```\n\n';
        }
      } else {
        md += '```text\n' + joined + '\n```\n\n';
      }
      md += '</details>\n\n';
    }
  } catch(e){
    md += '```text\n' + triageRaw.slice(0,10000) + '\n```\n\n';
  }
} else {
  md += '_No detailed triage JSON available._\n\n';
}

md += '</details>\n\n';

md += '---\n\n';

// footer with generated timestamp
md += '*Generated by CI triage generator at ' + new Date().toISOString() + '*\n';

try {
  fs.writeFileSync(dest, md, 'utf8');
  console.log('Wrote triage summary to', dest);
} catch (e){ console.error('Failed to write triage summary', e); process.exit(2); }

// also write plain text fallback to runner temp triage-summary.txt for compatibility
try { fs.writeFileSync(path.join(runnerTemp,'triage-summary.txt'), md.replace(/<[^>]+>/g,''), 'utf8'); } catch(e){}

// Generate HTML output (non-destructive, same content logically)
function severityBadge(sev){
  const s = String((sev||'').toLowerCase());
  const color = s === 'critical' ? '#c53030' : (s === 'warning' ? '#d69e2e' : '#3182ce');
  return `<span style="display:inline-block;padding:4px 8px;border-radius:12px;background:${color};color:#fff;font-weight:600">${sev||'unknown'}</span>`;
}

let html = `<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Triage Summary</title>
<style>body{font-family:system-ui, -apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif;margin:20px;color:#111}table{border-collapse:collapse;width:100%;}th,td{border:1px solid #ddd;padding:8px;text-align:left}th{background:#f7fafc}pre{background:#f5f7fa;padding:12px;overflow:auto}</style>
</head><body>`;

html += `<h1>Triage Summary</h1><hr/>`;
html += `<h2>Overview</h2>`;
html += `<table><tr><th>Severity</th><th>Tags</th><th>Internal Errors</th><th>Timestamp</th></tr>`;
if (triage) {
  const severity = triage.severity || 'unknown';
  const tags = (triage.inferredTags||[]).join(', ') || 'none';
  const errCount = (triage.internalErrors||[]).length || 0;
  const timestamp = triage.timestamp || new Date().toISOString();
  html += `<tr><td>${severityBadge(severity)}</td><td>${tags}</td><td style="text-align:right">${errCount}</td><td>${timestamp}</td></tr>`;
} else {
  html += `<tr><td>unknown</td><td>none</td><td style="text-align:right">0</td><td>-</td></tr>`;
}
html += `</table>`;

html += `<h3>Summary</h3><p>${shortSummaryFrom(triage)}</p>`;
if (issueLine) html += `<p><strong>Issue:</strong> ${issueLine}</p>`;

html += `<hr/><details><summary>Details (expand for full JSON and internal errors)</summary>`;
if (triageRaw){
  try {
    const parsed = JSON.parse(triageRaw);
    html += `<h4>triage.json</h4><pre><code>${escapeHtml(JSON.stringify(parsed,null,2))}</code></pre>`;
    const internal = (parsed.internalErrors||[]).map(e=>String(e));
    if (internal.length){
      html += `<details><summary>Internal Errors (${internal.length})</summary><pre><code>${escapeHtml(internal.join('\n\n'))}</code></pre></details>`;
    }
  } catch(e){
    html += `<pre><code>${escapeHtml(triageRaw.slice(0,10000))}</code></pre>`;
  }
} else {
  html += '<p>No detailed triage JSON available.</p>';
}
html += `</details><hr/><footer><small>Generated by CI triage generator at ${new Date().toISOString()}</small></footer></body></html>`;

function escapeHtml(s){ return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

try {
  const htmlPath = path.join(runnerTemp, 'triage-summary.html');
  fs.writeFileSync(htmlPath, html, 'utf8');
  console.log('Wrote triage HTML to', htmlPath);
} catch(e){ console.error('Failed to write triage HTML', e); }

// Generate compact comment text (Overview + Summary) for Issue comments
try {
  const commentPath = path.join(runnerTemp, 'triage-summary-comment.txt');
  const sev = triage && triage.severity ? triage.severity : 'unknown';
  const tags = triage && triage.inferredTags ? (triage.inferredTags||[]).join(', ') : 'none';
  const errs = triage && triage.internalErrors ? (triage.internalErrors||[]).length : 0;
  const ts = triage && triage.timestamp ? triage.timestamp : new Date().toISOString();
  const summ = shortSummaryFrom(triage);
  const commentBody = [`Severity: ${sev}`, `Tags: ${tags}`, `Internal Errors: ${errs}`, `Timestamp: ${ts}`, '', 'Summary:', summ].join('\n');
  fs.writeFileSync(commentPath, commentBody, 'utf8');
  console.log('Wrote triage comment to', commentPath);
} catch(e){ console.error('Failed to write triage comment', e); }

// Create gzip compressed copies of the summary outputs for archival
try {
  const files = [
    { src: path.join(runnerTemp,'triage-summary.md'), dst: path.join(runnerTemp,'triage-summary.md.gz') },
    { src: path.join(runnerTemp,'triage-summary.txt'), dst: path.join(runnerTemp,'triage-summary.txt.gz') },
    { src: path.join(runnerTemp,'triage-summary.html'), dst: path.join(runnerTemp,'triage-summary.html.gz') }
  ];
  files.forEach(f=>{
    try {
      if (fs.existsSync(f.src)){
        const raw = fs.readFileSync(f.src);
        const gz = zlib.gzipSync(raw, { level: 9 });
        fs.writeFileSync(f.dst, gz);
        console.log('Wrote gzip', f.dst);
      }
    } catch(e){ console.error('gzip failed for', f.src, e); }
  });
} catch(e){ console.error('Failed to write compressed summaries', e); }
